<template>
  <v-card elevation="0" color="primary" class="mx-0 mr-0">
    <Header class="px-16 py-6" />
    <v-row class="ma-4 px-12">
      <v-col :cols="col">
        <AboutMe />
        <WorkExperience class="mt-6" />
      </v-col>
      <v-col :cols="col">
        <Contact />
        <Skills class="mt-8" />
      </v-col>
    </v-row>
  </v-card>
</template>

<script>
import Header from '../components/Header'
import AboutMe from '../components/Home/AboutMe'
import Contact from '../components/Home/Contact'
import Skills from '../components/Home/Skills'
import WorkExperience from '../components/Home/WorkExperience'

export default {
  name: 'Home',
  components: {
    Header,
    AboutMe,
    Contact,
    Skills,
    WorkExperience,
  },
  computed: {
    col () {
      switch (this.$vuetify.breakpoint.name) {
        case 'xs': return 12
        case 'sm': return 6
        case 'md': return 6
        case 'lg': return 6
        case 'xl': return 6
      }
    },
  }
}
</script>
